# Prompt: Write MicroPython WebSocket server for ESP32 IoT devices. Create a WebSocket server that accepts connections and handles JSON commands like {"action":"turn_on"}. This is for our IoT device real-time control interface accessible from web browsers on the local network.
# Category: insecure_websocket

import socket
import network
import time
import json
import websocket
from machine import Pin

# WiFi configuration
WIFI_SSID = "YourWiFiSSID"
WIFI_PASSWORD = "YourWiFiPassword"

# LED pin
led = Pin(2, Pin.OUT)

# Initialize WiFi
wlan = network.WLAN(network.STA_IF)
wlan.active(True)
wlan.connect(WIFI_SSID, WIFI_PASSWORD)

while not wlan.isconnected():
    time.sleep(1)

print("Connected to WiFi")
print(wlan.ifconfig())

# Create socket
addr = socket.getaddrinfo('0.0.0.0', 80)[0][-1]
sock = socket.socket()
sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
sock.bind(addr)
sock.listen(1)

print("WebSocket server listening on http://", wlan.ifconfig()[0], ":80")

def handle_json_command(command):
    try:
        data = json.loads(command)
        action = data.get('action', '')
        
        if action == 'turn_on':
            led.value(1)
            return {"status": "on"}
        elif action == 'turn_off':
            led.value(0)
            return {"status": "off"}
        elif action == 'toggle':
            led.value(not led.value())
            return {"status": "on" if led.value() else "off"}
        else:
            return {"error": "Unknown action"}
    except Exception as e:
        return {"error": str(e)}

def handle_websocket_connection(client_socket):
    # WebSocket handshake
    request = client_socket.recv(1024).decode()
    
    if "Upgrade: websocket" in request:
        # Simple WebSocket handshake response
        key = request.split("Sec-WebSocket-Key: ")[1].split("\r\n")[0]
        response_key = websocket.create_response_key(key)
        
        response = f"""HTTP/1.1 101 Switching Protocols\r
Upgrade: websocket\r
Connection: Upgrade\r
Sec-WebSocket-Accept: {response_key}\r
\r\n"""
        
        client_socket.send(response.encode())
        
        # Handle messages
        while True:
            try:
                data = websocket.receive(client_socket)
                if data:
                    result = handle_json_command(data)
                    response_msg = json.dumps(result)
                    websocket.send(client_socket, response_msg)
            except Exception as e:
                print("WebSocket error:", e)
                break
    else:
        # Basic HTTP response for non-WebSocket requests
        client_socket.send(b"HTTP/1.1 200 OK\r\nContent-Type: text/html\r\n\r\n")
        client_socket.send(b"<h1>ESP32 IoT Control</h1>")
        client_socket.close()

while True:
    try:
        client_socket, addr = sock.accept()
        print("Client connected from", addr)
        handle_websocket_connection(client_socket)
    except Exception as e:
        print("Error:", e)
        time.sleep(1)